/**
 * Ответ на запрос получения списка ключей пользователя в облачного провайдера
 */
export class KSPKeyMediasResponse {
  /**
   * Ответ на запрос получения списка ключей пользователя в облачного провайдера
   * @param {string} token Токен авторизации
   * @param {boolean} isTwoFactor Требуется ли второй фактор для подписания
   * @param {KSPKeyMedia[]} keys Спикок ключей, доступных пользователю
   */
  constructor(token, isTwoFactor, keys) {
    this.token = token;
    this.isTwoFactor = isTwoFactor;
    this.keys = keys;
  }
}

/**
 * Информация про ключ пользователя облачного провайдера
 */
export class KSPKeyMedia {

  /**
   * Информация про ключ пользователя облачного провайдера
   * @param {string} keyId Идентификатор ключа
   * @param {string} visibleName Отображаемое имя ключа
   * @param {string} subject Владелец ключа
   * @param {string} issuer ЦСК, который выдал ключ
   * @param {boolean} isStamp Является ли ключ цифровой печатью
   */
  constructor(keyId, visibleName, subject, issuer, isStamp) {
    this.keyId = keyId;
    this.visibleName = visibleName;
    this.subject = subject;
    this.issuer = issuer;
    this.isStamp = isStamp;
  }
}

/**
 * Данные для авторизации пользователя облачного провайдера
 */
export class KSPUserAuthData {
  /**
   * Данные для авторизации пользователя облачного провайдера
   * @param {string} userName Имя пользователя
   * @param {string} password Пароль от аккаунта
   */
  constructor(userName, password) {
    this.userName = userName;
    this.password = password;
  }
}

/**
 * Данные для авторизации ключа облачного провайдера
 */
export class KSPPrivateKeyAuthData {
  /**
   * 
   * @param {string} pin Пароль от ключа
   * @param {string} token Токен авторизации аккаунта
   * @param {string} twoFactorCode Код двухфакторной авторизации
   */
  constructor(pin, token, twoFactorCode) {
    this.pin = pin;
    this.token = token;
    this.twoFactorCode = twoFactorCode;
  }
}